%[text] # Workflow reconstruction
%[text] 
%[text] First, load in a dataset for reconstruction. This needs to contain the detector x and y coordinates as well as a way to identify individual ions for their respective volume. Also load all auxilliary information such as a color scheme and an isotopic table. The isotopic table contains the information about the volume occupied by each ion.
load('isotopeTable_naturalAbundances.mat');
load('colorScheme.mat');

% picking epos file
[file, path] = uigetfile('*.epos');
pos = posToTable([path file]);
  %[control:button:0488]{"position":[1,2]}
%%
%[text] picking and allocating ranges
[file, path] = uigetfile('*.fig');
rngFig = openfig([path file],'visible');
spec = findobj(rngFig,'DisplayName','mass spectrum');
% allocation of ranges
pos = posAllocateRange(pos,rangesExtractFromMassSpec(spec),'raw');
% calculation of ion volumes based on atomic densities of the elements
[ionVolumes, pos] = ionVolumesFromAtomVolumes(pos,isotopeTable);
  %[control:button:9d9d]{"position":[1,2]}
%%
%[text] ## Reflectron image transformation
%[text] for reflectron instruments, a correction of the atomic hit coordinates must be carried out in order to account for the imaging properties of the reflectron. This transforms the detector hit coordinates onto a 'virtual detector', located 5.5 mm behind the specimen. The calibration file is specific to an instrument or instrument series.
%load('LEAP4000XHR_calibrationGrid.mat');
pos = reflectronImageTransform(pos, intersections);
  %[control:button:6b12]{"position":[1,2]}
%%
%[text] ## Straight flight path image compression correction
%[text] In most straight flight path instruments, the detector sits at an electrostatic potential that is different than its surrounding. This leads to changing image compression as the specimen voltage changes. We can correct for this by using a master curve relative to a reference potential. 
load('LEAP3000_4000Si_imageCompression.mat');
areaCompressionFactor = vmodel(pos.VDC);
linearCompressionFactor = sqrt(areaCompressionFactor);
pos.detx = pos.detx ./ linearCompressionFactor;
pos.dety = pos.dety ./ linearCompressionFactor;
  %[control:button:9486]{"position":[1,2]}
%%
%[text] ## Creating a detector hull
%[text] In order to have a measurement of the effective detector area that ions impact on and to determine the boundary of the dataset, we can create a hull for the dataset in detector space. This hull is then co-reconstructed with the rest of the data.
hullPara.alphaRadius = 10; % alpha radius for each detector segment in the hit sequence
hullPara.approxNumAtomPerSegment = 1E6; % approximate number of atoms per segment of the hull
hullPara.numSeg = round(height(pos)/hullPara.approxNumAtomPerSegment); % number of detector segments in the hit sequence. Here: about every 1M atoms
hullPara.nGon = 32; % number of boundary vertices in each detector segment
hullPara.capLoops = 4; % number of edge loops on top and bottom caps
hullPara.useVoronoiFilter = false; % if detector is unfilled, filter stray 'ghost' hits. Can take a while.
hullPara.filterNoiseLimit = 0.05; % fraction of hits with large Voronoi areas that define filter threshold.

[hullDetector, Area] = detectorHull(pos, hullPara.alphaRadius, hullPara.numSeg, hullPara.nGon, hullPara.capLoops, hullPara.useVoronoiFilter, hullPara.filterNoiseLimit); %[output:977b9889]
  %[control:button:14c7]{"position":[1,2]}
%%
%[text] ## Reconstruction setup
%[text] instrument / experiment parameters
%[text] For reflectron corrected datasets - the flight path length is the length between the tip and the end of the electrode, because after the correction - we have no reflectron in our datasets - consequentley the value     is assumed / measured
reconPara.effectiveDetectorArea = 2.5^2*pi()/4; % area of the detector that is used in mm2
reconPara.detectorEfficiency = 0.37; % fraction of atoms captured by the detector
reconPara.flightPathLength = 3.5; % either physical or virtual 
%% for reflectron corrected dataset a flight path length between 3.3 and 3.8 should be used
reconPara.imageCompressionFactor = 1.8; % factor the image on the detector is smaller than if it would be if the ions flew in a straight line %[control:slider:651b]{"position":[36,39]}
ionVolume = pos.ionVolume; %ones([height(pos) 1]) * 70; % volume each ion takes up in the material
reconPara.species = {'W'}; % species used for visualisatoin of the reconstruction result
  %[control:button:1628]{"position":[1,2]}
%%
%[text] Calculation of radius evolution
reconPara.kf = 3.3; % field factor. Proportionality between the field of a charged sphere and that of a real specimen. %[control:slider:8b36]{"position":[16,19]}
reconPara.Fevap = 52; % evaporation field. Critical field above which field evaporation takes place. %[control:editfield:8251]{"position":[19,21]}
radius = pos.VDC ./ reconPara.kf ./ reconPara.Fevap; % resulting estimate of the radius evolution of the specimen
  %[control:button:715e]{"position":[1,2]}
%%
%[text] ## Reconstruction
[pos, hullR] = posReconstruct3DGeiser(...
    pos,reconPara.flightPathLength,reconPara.detectorEfficiency,reconPara.effectiveDetectorArea,pos.ionVolume,radius,reconPara.imageCompressionFactor,hullDetector);
  %[control:button:1026]{"position":[1,2]}
%%
%[text] ## Visualisation of reconstruction results
scatterPlotPosData(pos,reconPara.species,1,colorScheme); %[output:65c53f18]
hold on; %[output:65c53f18]
patch(hullR(1),'FaceColor',[0 0 1],'FaceAlpha',0.1); % hull mantle %[output:65c53f18]
patch(hullR(2),'FaceColor',[0 0 1],'FaceAlpha',0.1); % hull top cap %[output:65c53f18]
patch(hullR(3),'FaceColor',[0 0 1],'FaceAlpha',0.1); % hull bottom cap %[output:65c53f18]
  %[control:button:47cd]{"position":[1,2]}
%%
%[text] ## Inverse reconstruction (deconstruction)
%[text] In order to optimise reconstructions, we may outline objects in inperfect reconstructions as use them to guide subsequent reconstruction optimisations. To this end, we can use a barycentric transformation to transform object vertex coordinates from reconstruction space to detector space. 
%[text] IMPORTANT: downsampling should be used for the pos and detector coordinated, as large datasets lead to excessive memory use and compute times. Downsampled dataset sizes of 10^5 - 10^6 are reasonable on a machine with 16GB RAM.
numSampledAtoms = 1E5;
sample = sort(randsample(height(pos),numSampledAtoms));
fvDetector = fv;
fvDetector.vertices = reconstructionToDetectorCoordinates(fv.vertices,pos(sample,:));
%[text] visualisation of object in detector coordinates
figure;
patch(hullDetector(1),'FaceColor',[0 0 1],'FaceAlpha',0); % hull mantle
patch(hullDetector(2),'FaceColor',[0 0 1],'FaceAlpha',0); % hull top cap
patch(hullDetector(3),'FaceColor',[0 0 1],'FaceAlpha',0); % hull bottom cap
patch(fvDetector,'FaceColor',[0 1 1],'FaceAlpha',1); % deconstructed object
axis square;

